1	// Edge function: create-listing (US-053)
2	//
3	// Contract:
4	//   POST {
5	//     title:           string (1..200 after trim),
6	//     description:     string (1..5000 after trim),
7	//     price_cents:     number (integer, >= 0, <= 1e9),
8	//     currency:        'USD' | 'EUR' | 'GBP',
9	//     max_submissions: number | null (integer, 1..99999),
10	//     pre_conditions: Array<{
11	//       platform: 'tiktok' | 'instagram',
12	//       metric:   'followers' | 'avg_views',
13	//       threshold: number (integer, >= 0),
14	//     }>,
15	//     post_conditions: Array<{ id: string (uuid), text: string (1..500 trim) }>,
16	//     sample_urls:     Array<string>  // each must classify as tiktok|instagram
17	//   }
18	//     → 201 { listing_id: string, version_id: string }
19	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST', field?: string }
20	//     → 401 { error: 'UNAUTHORIZED' }
21	//     → 403 { error: 'FORBIDDEN' }                 // non-lister role
22	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
23	//
24	// Auth: Marketify HS256 JWT (MARKETIFY_JWT_SECRET), app_role must be 'lister'.
25	//       Gateway `verify_jwt` is disabled because Supabase-issued JWTs aren't
26	//       the same namespace — the handler enforces auth via _shared/jwt.ts.
27	//
28	// The handler is the validation boundary: the RPC assumes caller has already
29	// normalized shape. We classify sample URLs here (via _shared/oembed.ts) so
30	// the DB sees the same platform label the wizard preview showed the user.
31	// Empty / whitespace-only URL rows are dropped silently (the wizard allows
32	// blank rows as drafting state per US-052).
33	
34	import { createClient } from "npm:@supabase/supabase-js@2";
35	import { verifyJwt } from "../_shared/jwt.ts";
36	import { corsHeaders } from "../_shared/cors.ts";
37	import { classifyVideoUrl } from "../_shared/oembed.ts";
38	
39	const UUID_RE =
40	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
41	
42	const TITLE_MIN = 1;
43	const TITLE_MAX = 200;
44	const DESCRIPTION_MIN = 1;
45	const DESCRIPTION_MAX = 5000;
46	const PRICE_CENTS_MAX = 1_000_000_000;
47	const MAX_SUBMISSIONS_MAX = 99_999;
48	const POST_TEXT_MAX = 500;
49	const PRE_CONDITIONS_MAX = 10;
50	const POST_CONDITIONS_MAX = 20;
51	const SAMPLE_URLS_MAX = 10;
52	const ALLOWED_CURRENCIES = new Set(["USD", "EUR", "GBP"]);
53	const ALLOWED_PRE_PLATFORMS = new Set(["tiktok", "instagram"]);
54	const ALLOWED_PRE_METRICS = new Set(["followers", "avg_views"]);
55	
56	interface RawRequest {
57	  title?: unknown;
58	  description?: unknown;
59	  price_cents?: unknown;
60	  currency?: unknown;
61	  max_submissions?: unknown;
62	  pre_conditions?: unknown;
63	  post_conditions?: unknown;
64	  sample_urls?: unknown;
65	}
66	
67	interface RawPreCondition {
68	  platform?: unknown;
69	  metric?: unknown;
70	  threshold?: unknown;
71	}
72	
73	interface RawPostCondition {
74	  id?: unknown;
75	  text?: unknown;
76	}
77	
78	interface NormalizedPayload {
79	  title: string;
80	  description: string;
81	  price_cents: number;
82	  currency: string;
83	  max_submissions: number | null;
84	  pre_conditions: Array<{
85	    platform: "tiktok" | "instagram";
86	    metric: "followers" | "avg_views";
87	    threshold: number;
88	  }>;
89	  post_conditions: Array<{ id: string; text: string }>;
90	  sample_videos: Array<{ platform: "tiktok" | "instagram"; url: string }>;
91	}
92	
93	function jsonResponse(status: number, body: unknown): Response {
94	  return new Response(JSON.stringify(body), {
95	    status,
96	    headers: { ...corsHeaders, "Content-Type": "application/json" },
97	  });
98	}
99	
100	function bearerToken(req: Request): string | null {
101	  const raw = req.headers.get("Authorization") ??
102	    req.headers.get("authorization");
103	  if (!raw) return null;
104	  const m = raw.match(/^Bearer\s+(.+)$/i);
105	  return m ? m[1].trim() : null;
106	}
107	
108	function isNonNegativeSafeInt(n: unknown, max: number): n is number {
109	  return typeof n === "number" && Number.isFinite(n) && Number.isInteger(n) &&
110	    n >= 0 && n <= max;
111	}
112	
113	function validate(body: RawRequest):
114	  | { ok: true; payload: NormalizedPayload }
115	  | { ok: false; field: string } {
116	  if (typeof body.title !== "string") return { ok: false, field: "title" };
117	  const title = body.title.trim();
118	  if (title.length < TITLE_MIN || title.length > TITLE_MAX) {
119	    return { ok: false, field: "title" };
120	  }
121	
122	  if (typeof body.description !== "string") {
123	    return { ok: false, field: "description" };
124	  }
125	  const description = body.description.trim();
126	  if (
127	    description.length < DESCRIPTION_MIN ||
128	    description.length > DESCRIPTION_MAX
129	  ) {
130	    return { ok: false, field: "description" };
131	  }
132	
133	  if (!isNonNegativeSafeInt(body.price_cents, PRICE_CENTS_MAX)) {
134	    return { ok: false, field: "price_cents" };
135	  }
136	  const priceCents = body.price_cents;
137	
138	  if (typeof body.currency !== "string" || !ALLOWED_CURRENCIES.has(body.currency)) {
139	    return { ok: false, field: "currency" };
140	  }
141	  const currency = body.currency;
142	
143	  let maxSubmissions: number | null = null;
144	  if (body.max_submissions !== null && body.max_submissions !== undefined) {
145	    if (
146	      typeof body.max_submissions !== "number" ||
147	      !Number.isInteger(body.max_submissions) ||
148	      body.max_submissions < 1 ||
149	      body.max_submissions > MAX_SUBMISSIONS_MAX
150	    ) {
151	      return { ok: false, field: "max_submissions" };
152	    }
153	    maxSubmissions = body.max_submissions;
154	  }
155	
156	  if (!Array.isArray(body.pre_conditions)) {
157	    return { ok: false, field: "pre_conditions" };
158	  }
159	  if (body.pre_conditions.length > PRE_CONDITIONS_MAX) {
160	    return { ok: false, field: "pre_conditions" };
161	  }
162	  const preConditions: NormalizedPayload["pre_conditions"] = [];
163	  for (const rawRow of body.pre_conditions) {
164	    const row = rawRow as RawPreCondition;
165	    if (typeof row !== "object" || row === null) {
166	      return { ok: false, field: "pre_conditions" };
167	    }
168	    if (typeof row.platform !== "string" || !ALLOWED_PRE_PLATFORMS.has(row.platform)) {
169	      return { ok: false, field: "pre_conditions.platform" };
170	    }
171	    if (typeof row.metric !== "string" || !ALLOWED_PRE_METRICS.has(row.metric)) {
172	      return { ok: false, field: "pre_conditions.metric" };
173	    }
174	    if (!isNonNegativeSafeInt(row.threshold, Number.MAX_SAFE_INTEGER)) {
175	      return { ok: false, field: "pre_conditions.threshold" };
176	    }
177	    preConditions.push({
178	      platform: row.platform as "tiktok" | "instagram",
179	      metric: row.metric as "followers" | "avg_views",
180	      threshold: row.threshold,
181	    });
182	  }
183	
184	  if (!Array.isArray(body.post_conditions)) {
185	    return { ok: false, field: "post_conditions" };
186	  }
187	  if (body.post_conditions.length > POST_CONDITIONS_MAX) {
188	    return { ok: false, field: "post_conditions" };
189	  }
190	  const postConditions: NormalizedPayload["post_conditions"] = [];
191	  const seenPostIds = new Set<string>();
192	  for (const rawRow of body.post_conditions) {
193	    const row = rawRow as RawPostCondition;
194	    if (typeof row !== "object" || row === null) {
195	      return { ok: false, field: "post_conditions" };
196	    }
197	    if (typeof row.id !== "string" || !UUID_RE.test(row.id)) {
198	      return { ok: false, field: "post_conditions.id" };
199	    }
200	    if (seenPostIds.has(row.id)) {
201	      return { ok: false, field: "post_conditions.id" };
202	    }
203	    seenPostIds.add(row.id);
204	    if (typeof row.text !== "string") {
205	      return { ok: false, field: "post_conditions.text" };
206	    }
207	    const text = row.text.trim();
208	    if (text.length === 0 || text.length > POST_TEXT_MAX) {
209	      return { ok: false, field: "post_conditions.text" };
210	    }
211	    postConditions.push({ id: row.id, text });
212	  }
213	
214	  if (!Array.isArray(body.sample_urls)) {
215	    return { ok: false, field: "sample_urls" };
216	  }
217	  if (body.sample_urls.length > SAMPLE_URLS_MAX) {
218	    return { ok: false, field: "sample_urls" };
219	  }
220	  const sampleVideos: NormalizedPayload["sample_videos"] = [];
221	  for (const rawUrl of body.sample_urls) {
222	    if (typeof rawUrl !== "string") {
223	      return { ok: false, field: "sample_urls" };
224	    }
225	    const trimmed = rawUrl.trim();
226	    // Empty rows are wizard drafting state — drop silently so the user
227	    // doesn't need to explicitly remove them before tapping Publish.
228	    if (trimmed.length === 0) continue;
229	    const classification = classifyVideoUrl(trimmed);
230	    if (!classification) {
231	      return { ok: false, field: "sample_urls" };
232	    }
233	    sampleVideos.push({ platform: classification.platform, url: trimmed });
234	  }
235	
236	  return {
237	    ok: true,
238	    payload: {
239	      title,
240	      description,
241	      price_cents: priceCents,
242	      currency,
243	      max_submissions: maxSubmissions,
244	      pre_conditions: preConditions,
245	      post_conditions: postConditions,
246	      sample_videos: sampleVideos,
247	    },
248	  };
249	}
250	
251	Deno.serve(async (req) => {
252	  if (req.method === "OPTIONS") {
253	    return new Response(null, { status: 204, headers: corsHeaders });
254	  }
255	  if (req.method !== "POST") {
256	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
257	  }
258	
259	  const token = bearerToken(req);
260	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
261	
262	  let claims;
263	  try {
264	    claims = await verifyJwt(token);
265	  } catch {
266	    return jsonResponse(401, { error: "UNAUTHORIZED" });
267	  }
268	  if (claims.app_role !== "lister") {
269	    return jsonResponse(403, { error: "FORBIDDEN" });
270	  }
271	
272	  let raw: RawRequest;
273	  try {
274	    raw = await req.json();
275	  } catch {
276	    return jsonResponse(400, { error: "INVALID_JSON" });
277	  }
278	
279	  const result = validate(raw);
280	  if (!result.ok) {
281	    return jsonResponse(400, { error: "INVALID_REQUEST", field: result.field });
282	  }
283	
284	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
285	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
286	  if (!supabaseUrl || !serviceRoleKey) {
287	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
288	  }
289	
290	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
291	    auth: { persistSession: false, autoRefreshToken: false },
292	  });
293	
294	  const { data: rpcData, error: rpcError } = await supabase.rpc(
295	    "create_listing_rpc",
296	    {
297	      p_lister_id: claims.sub,
298	      p_payload: result.payload as unknown as Record<string, unknown>,
299	    },
300	  );
301	
302	  if (rpcError) {
303	    console.error("create_listing_rpc error", rpcError);
304	    return jsonResponse(500, { error: "DB_ERROR" });
305	  }
306	
307	  const shaped = rpcData as
308	    | { listing_id?: string; version_id?: string }
309	    | null;
310	  if (!shaped?.listing_id || !shaped.version_id) {
311	    console.error("create_listing_rpc returned unexpected shape", rpcData);
312	    return jsonResponse(500, { error: "DB_ERROR" });
313	  }
314	
315	  return jsonResponse(201, {
316	    listing_id: shaped.listing_id,
317	    version_id: shaped.version_id,
318	  });
319	});
