1	import { useCallback, useMemo, useRef, useState } from 'react';
2	import {
3	  Pressable,
4	  SafeAreaView,
5	  ScrollView,
6	  StyleSheet,
7	  Text,
8	  View,
9	} from 'react-native';
10	import { router } from 'expo-router';
11	import { ChevronLeft } from 'lucide-react-native';
12	import { ButtonPrimary } from '@/components/primitives/Button';
13	import { useToast } from '@/components/primitives/Toast';
14	import { colors, radii, shadows, spacing } from '@/design/tokens';
15	import { textStyles } from '@/design/typography';
16	import { classifyVideoUrl } from '@/lib/oembed';
17	import { supabase } from '@/lib/supabase';
18	import {
19	  useWizard,
20	  type WizardCurrency,
21	  type WizardDraft,
22	  type WizardPreConditionMetric,
23	  type WizardPreConditionPlatform,
24	} from '@/screens/campaign-wizard/WizardStore';
