26	// US-053 — Create-campaign wizard step 5 (review + publish). Renders the draft
27	// as a creator would see it (via the same primitives the detail screen uses
28	// in spirit — neubrutalist cards, sectioned sample videos, pre/post rules),
29	// then POSTs the normalized payload to the `create-listing` edge function.
30	//
31	// Payload shape mirrors the edge function contract in
32	// `supabase/functions/create-listing/index.ts`. We do a final client-side
33	// validation pass (title/description non-empty after trim, each pre-condition
34	// threshold > 0, each post-condition text non-empty, each sample URL that
35	// survives the filter is recognized by `classifyVideoUrl`) so the Publish CTA
36	// surfaces a local reason when the wizard isn't in a shippable state and the
37	// server never sees an obvious-reject request.
38	//
39	// On 201 we drop the AsyncStorage draft via `resetDraft`, show a success toast,
40	// and route-replace to the Campaigns tab so Back doesn't return to step-5.
41	// Any other outcome lands as an error toast; the draft is preserved so the
42	// user can retry without re-keying everything (Codebase Pattern #128 — the
43	// wizard persists on every edit, so even if the app backgrounds during a
44	// retry the state is safe).
45	
46	const CURRENCY_SYMBOL: Record<WizardCurrency, string> = {
47	  USD: '$',
48	  EUR: '€',
49	  GBP: '£',
50	};
51	
52	const METRIC_LABEL: Record<WizardPreConditionMetric, string> = {
53	  followers: 'Followers',
54	  avg_views: 'Avg views',
55	};
56	
57	const PLATFORM_LABEL: Record<WizardPreConditionPlatform, string> = {
58	  tiktok: 'TikTok',
59	  instagram: 'Instagram',
60	};
61	
62	type PublishRequest = {
63	  title: string;
64	  description: string;
65	  price_cents: number;
66	  currency: WizardCurrency;
67	  max_submissions: number | null;
68	  pre_conditions: {
69	    platform: WizardPreConditionPlatform;
70	    metric: WizardPreConditionMetric;
71	    threshold: number;
72	  }[];
73	  post_conditions: { id: string; text: string }[];
74	  sample_urls: string[];
75	};
76	
77	type PublishSuccess = {
78	  listing_id: string;
79	  version_id: string;
80	};
81	
82	type ServerErrorBody = {
83	  error?: string;
84	  field?: string;
85	};
86	
87	// Returns either a request body ready for the edge function OR a human-
88	// readable reason the current draft isn't shippable. Empty sample rows are
89	// filtered out (mirrors the server) and whitespace-only text fields reject
90	// locally so the user sees the failure before the network round-trip.
91	function buildRequest(
92	  draft: WizardDraft,
93	): { ok: true; body: PublishRequest } | { ok: false; reason: string } {
94	  const title = draft.title.trim();
95	  if (title.length === 0) return { ok: false, reason: 'Add a title in step 1.' };
96	  const description = draft.description.trim();
97	  if (description.length === 0) {
98	    return { ok: false, reason: 'Add a description in step 1.' };
99	  }
100	
101	  for (const row of draft.preConditions) {
102	    if (!Number.isFinite(row.threshold) || row.threshold <= 0) {
103	      return {
104	        ok: false,
105	        reason: 'Each eligibility rule needs a threshold above 0.',
106	      };
107	    }
108	  }
109	
110	  const postConditions: { id: string; text: string }[] = [];
111	  for (const row of draft.postConditions) {
112	    const text = row.text.trim();
113	    if (text.length === 0) {
114	      return { ok: false, reason: 'Fill in every content rule or remove it.' };
115	    }
116	    postConditions.push({ id: row.id, text });
117	  }
118	
119	  const sampleUrls: string[] = [];
120	  for (const raw of draft.sampleUrls) {
121	    const trimmed = raw.trim();
122	    if (trimmed.length === 0) continue;
123	    if (!classifyVideoUrl(trimmed)) {
124	      return {
125	        ok: false,
126	        reason: 'Sample URLs must be TikTok or Instagram videos.',
127	      };
128	    }
129	    sampleUrls.push(trimmed);
130	  }
131	
132	  return {
133	    ok: true,
134	    body: {
135	      title,
136	      description,
137	      price_cents: draft.priceCents ?? 0,
138	      currency: draft.currency,
139	      max_submissions: draft.maxSubmissions,
140	      pre_conditions: draft.preConditions.map((row) => ({
141	        platform: row.platform,
142	        metric: row.metric,
143	        threshold: row.threshold,
144	      })),
145	      post_conditions: postConditions,
146	      sample_urls: sampleUrls,
147	    },
148	  };
149	}
150	
151	function formatPrice(cents: number | null, currency: WizardCurrency): string {
152	  if (cents === null) return 'Not set';
153	  const symbol = CURRENCY_SYMBOL[currency];
154	  if (cents % 100 === 0) return `${symbol}${cents / 100}`;
155	  return `${symbol}${(cents / 100).toFixed(2)}`;
156	}
157	
158	function formatThreshold(n: number): string {
159	  // 5,000 → "5,000". Keeps the review screen readable for large thresholds
160	  // without a third-party number formatter.
161	  return n.toLocaleString('en-US');
162	}
163	
164	async function readErrorBody(error: unknown): Promise<ServerErrorBody | null> {
165	  // Pattern #98 — FunctionsHttpError carries the raw Response on `.context`.
166	  const ctx = (error as { context?: unknown }).context;
167	  if (
168	    !ctx ||
169	    typeof ctx !== 'object' ||
170	    !('status' in ctx) ||
171	    typeof (ctx as { json?: unknown }).json !== 'function'
172	  ) {
173	    return null;
174	  }
175	  try {
176	    return (await (ctx as Response).json()) as ServerErrorBody;
177	  } catch {
178	    return null;
179	  }
180	}
181	
182	export default function CampaignWizardStep5() {
183	  const { draft, resetDraft } = useWizard();
184	  const { show: showToast } = useToast();
185	  const submittingRef = useRef(false);
186	  const [submitting, setSubmitting] = useState(false);
187	
188	  const validation = useMemo(() => buildRequest(draft), [draft]);
189	  const canPublish = validation.ok && !submitting;
190	
191	  const onBack = useCallback(() => {
192	    if (router.canGoBack()) router.back();
193	    else router.replace('/(lister)/campaigns/new/step-4');
194	  }, []);
195	
196	  const onPublish = useCallback(async () => {
197	    if (submittingRef.current) return;
198	    if (!validation.ok) {
199	      showToast({ message: validation.reason, variant: 'error' });
200	      return;
201	    }
202	    submittingRef.current = true;
203	    setSubmitting(true);
204	    try {
205	      const { data, error } = await supabase.functions.invoke<PublishSuccess>(
206	        'create-listing',
207	        { body: validation.body },
208	      );
209	
210	      if (error) {
211	        const body = await readErrorBody(error);
212	        const message = body?.error === 'INVALID_REQUEST' && body.field
213	          ? `Please re-check ${body.field.replaceAll('_', ' ')}.`
214	          : "Couldn't publish. Try again.";
215	        showToast({ message, variant: 'error' });
216	        return;
217	      }
218	
219	      if (!data?.listing_id) {
220	        showToast({
221	          message: "Couldn't publish. Try again.",
222	          variant: 'error',
223	        });
224	        return;
225	      }
226	
227	      // Clear persisted draft before navigating so the wizard boots fresh if
228	      // the lister taps the FAB again. `replace` (not `push`) so Back from
229	      // Campaigns doesn't bounce into a now-stale review screen.
230	      await resetDraft();
231	      showToast({ message: 'Campaign published.', variant: 'success' });
232	      router.replace('/(lister)/campaigns');
233	    } catch (err) {
234	      console.error('create-listing threw', err);
235	      showToast({ message: "Couldn't publish. Try again.", variant: 'error' });
236	    } finally {
237	      submittingRef.current = false;
238	      setSubmitting(false);
239	    }
240	  }, [validation, showToast, resetDraft]);
241	
242	  const visibleSampleUrls = draft.sampleUrls.filter((u) => u.trim().length > 0);
243	
244	  return (
245	    <SafeAreaView style={styles.root}>
246	      <ScrollView
247	        contentContainerStyle={styles.scroll}
248	        keyboardShouldPersistTaps="handled"
249	      >
250	        <View style={styles.header}>
251	          <Pressable
252	            onPress={onBack}
253	            hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
254	            accessibilityRole="button"
255	            accessibilityLabel="Back"
256	            testID="wizard-step5-back"
257	            style={styles.backBtn}
258	          >
259	            <ChevronLeft size={24} color={colors.ink} />
260	          </Pressable>
261	          <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
262	            Step 5 of 5
263	          </Text>
264	          <Text style={[textStyles.display, styles.title]} maxFontSizeMultiplier={1.3}>
265	            Review & publish
266	          </Text>
267	          <Text style={[textStyles.body, styles.subtitle]} maxFontSizeMultiplier={1.3}>
268	            Here&apos;s what creators will see when they open your campaign.
269	          </Text>
270	        </View>
271	
272	        <View style={[styles.card, shadows.hard]} testID="wizard-step5-basics">
273	          <Text style={[textStyles.caption, styles.sectionLabel]} maxFontSizeMultiplier={1.3}>
274	            Basics
275	          </Text>
276	          <Text style={[textStyles.display, styles.bigTitle]} maxFontSizeMultiplier={1.3}>
277	            {draft.title.trim().length > 0 ? draft.title : 'Untitled campaign'}
278	          </Text>
279	          <Text style={[textStyles.body, styles.descriptionText]} maxFontSizeMultiplier={1.3}>
280	            {draft.description.trim().length > 0
281	              ? draft.description
282	              : 'No description yet.'}
283	          </Text>
284	          <View style={styles.metaRow}>
285	            <View style={styles.metaItem}>
